sys_variable_value.value:
(function(outputs, steps, stepResult, assertEqual) {
    var table = 'x_1839224_chroma_0_chromatech_sold_products'; // Confirm your table backend name
    var field = 'warranty_period_months_choice';
    var allowedValues = ['06', '12', '18', '24']; // The explicit choices
    var foundValues = [];
    var unauthorized = [];

    var choiceGr = new GlideRecord('sys_choice');
    choiceGr.addQuery('name', table);
    choiceGr.addQuery('element', field);
    choiceGr.addQuery('inactive', false);
    choiceGr.query();

    while (choiceGr.next()) {
        var val = choiceGr.value.toString();
        foundValues.push(val);
        // Check if the choice record is one of our allowed integers
        if (allowedValues.indexOf(val) === -1) {
            unauthorized.push(val);
        }
    }

    // 1. Check for unauthorized records in sys_choice (excluding our integers)
    if (unauthorized.length > 0) {
        stepResult.setOutputMessage("FAILURE: Unauthorized choices found in database: " + unauthorized.join(', '));
        stepResult.setFailed();
        return;
    }

    // 2. Validate "None" option via Dictionary configuration
    var dictGr = new GlideRecord('sys_dictionary');
    dictGr.addQuery('name', table);
    dictGr.addQuery('element', field);
    dictGr.query();
    
    if (dictGr.next()) {
        // "choice" value 1 = Dropdown with -- None --
        // "choice" value 3 = Dropdown without -- None --
        if (dictGr.choice != '1') { 
            stepResult.setOutputMessage("FAILURE: Field is not configured to 'Dropdown with -- None --'. Current choice setting: " + dictGr.choice);
            stepResult.setFailed();
            return;
        }
    }

    stepResult.setOutputMessage("SUCCESS: Validated choices (6, 12, 18, 24) and verified '-- None --' is enabled.");
    stepResult.setSuccess();
})(outputs, steps, stepResult, assertEqual);
